properties.property:
[
	{
		"name": "",
		"text": "You are surprised to see what is clearly a vampiric crypt within the city walls. Even more strange, several vampiric attendants stand outside it. 'There is blood to be spilled, and blood to be recovered. Will you heed its call?'",
		"options":
			[
				{
					"name": "Sengir has been slain.",
                    "text": "The vampiric attendants rush inside with the bowl. An intimidating vampire woman with a fearsome aura strides out soon after. 'I must thank you for reviving me. Slaying the Baron was no easy feat, I'm certain. Now I can continue my eternal vigil over this city, as I swore to do so very long ago.'",
					"action": [ { "deleteMapObject": -1 },
                    {"grantRewards": [
						{"type": "life", "count": 1},
						{ "type": "card", "cardName": "Blood Money", "count": 1 },
                        { "type": "card", "cardName": "Bloodline Culling", "count": 1 },
                        { "type": "card", "cardName": "Sever the Bloodline", "count": 1 },
                        { "type": "card", "cardName": "Wine of Blood and Iron", "count": 1 },
                        { "type": "card", "cardName": "Thief of Blood", "count": 1 },
                        {"type": "gold", "count": 3000}          
                      ]
                    },
					{"removeItem":"Bowl of Ancient Blood"},
					{"addMapReputation": 4} ],
					"condition":[{"item":"Bowl of Ancient Blood"}], 
					"options": [ { "name": "(Continue)" } ]
				},
				{
					"name": "Depends on what exactly you mean by that.",
					"text": "'Not all vampires are solely devoted to cruelty. One such ancient protected our city until recently. But the bowl of ancient blood she supped upon so as not to need to slake her thirst upon our people has been stolen by a rival, the Dark Baron Sengir.'",
					"options": [ { "name": "Truly worthy of the title legend, that one.",
					"text": "'Certainly. He dwells in his castle elsewhere within the swamps, which looks quite similar to this one. Slay him and retrieve the bowl and you shall have the favor of our patroness and a fitting reward as well.'",
					"options": [ { "name": "Time to put an end to an elder vampire." } ]
					 }]
				},
                {
					"name": "You know, you're a bit creepy for my tastes.",
					"text": "'If you find us creepy, we suggest you leave the swamps while you still can.'",
					"options": [ { "name": "(Continue)" } ]
				}
			]
	}
]

[
	{
		"name": "",
		"text": "The intimidating building you've entered is staffed by a variety of menacing warlocks. 'You are, {var=player_name}, yes? We have heard whisperings of you. We are undecided if you are strong enough to undertake the task we need, but should you fail, perhaps you shall at least weaken our adversary.'",
		"options":
			[
				{
					"name": "Sheoldred is slain.",
                    "text": "'Your power was great indeed. Perhaps we may have future use for you, but for now, you have the reward you were promised, and our gratitude, though it may pain some of us to give it.'",
					"action": [ { "deleteMapObject": -1 },
                    {"grantRewards": [
						{"type": "life", "count": 1},
						{ "type": "card", "cardName": "Avenger of the Fallen", "count": 1 },
                        {"type": "gold", "count": 5000}          
                      ]
                    },
					{"removeItem":"Black Cartouche of Victory"},
					{"addMapReputation": 4} ],
					"condition":[{"item":"Black Cartouche of Victory"}], 
					"options": [ { "name": "(Continue)" } ]
				},
				{
					"name": "Let them whisper, I can face any foe.",
					"text": "'Excellent. We will not dither - the one that must die is the phyrexian praetor Sheoldred herself. The Whispering One. The Apocalypse. These eipthets are well-earned, but die she must. If you can make that happen, you will receive great favor from our city and a large sum of gold.'",
					"options": [ { "name": "Seems straightfoward enough, if difficult.",
					"text": "'Indeed. One more thing. Sheoldred has hidden the location of her stronghold from our scrying methods. but it is easy to spot should you come across it in your travels - it is a feastering wound on the land in the shape of the phyrexian sigil.'",
					"options": [ { "name": "Sheoldred shall fall by my hand." } ]
					 }]
				},
                {
					"name": "I have little interest in helping such disrespectful folks.",
					"text": "'So be it. We shall save our reward for a more ambitious soul.'",
					"options": [ { "name": "(Continue)" } ]
				}
			]
	}
]

[
	{
		"name": "",
		"text": "You enter what looks to be a temple to some dark god. A black-robed priestess, pale but beautiful turns towards you and speaks. 'The dark ones require a champion. Can you answer their call?'",
		"options":
			[
				{
					"name": "The three great threats are ended.",
                    "text": "'The dark ones are pleased! Their worshippers are now free to continue their supplication! You have the city's gratitude.'",
					"action": [ { "deleteMapObject": -1 },
                    {"grantRewards": [
	               {"type": "item", "count": 1, "itemName": "Massacre Helm"},
                        {"type": "card", "count": 1, "cardName": "Vampiric Tutor"},
                        {"type": "card", "count": 1, "cardName": "Yawgmoth's Bargain"}          
                      ]
                    },
					{"addMapReputation": 10}  ],
					"condition":[{"item": "Bloodsworn Bite"}, {"item": "Sinister Concoction"}, {"item": "Mask of Valgavoth"}], 
					"options": [ { "name": "(Continue)" } ]
				},
				{
					"name": "I don't know about the dark ones, but I can be a champion.",
					"text": "'There are many horrifically powerful legends that threaten the swamps. I offer three sacred treasures to any who can defeat the three worst.'",
					"options": [ { "name": "Which three are we speaking of?",
					"text": "'The vampiric progenitor, Edgar Markov. The terror eater Valgavoth. And the horror of Zhava, the Gitrog Monster. Slay them all and show me the relics they once possessed to receive the blessings of my dark god.'",
					"options": [ { "name": "I will see what I can do." } ]
					 }]
				},
                {
					"name": "Sounds a little sketchy.",
					"text": "'Well, if you acheive great feats, return and perhaps my prayers will be answered then.'",
					"options": [ { "name": "(Continue)" } ]
				}
			]
	}
]
